**File 2:** `sdk/computelimit/Azure.ResourceManager.ComputeLimit/tests/Samples/Sample1_VmFamilies.cs` — **create**

```csharp
// Copyright (c) Microsoft Corporation. All rights reserved.
// Licensed under the MIT License.

using System;
using System.Threading.Tasks;
using Azure.Identity;
using Azure.ResourceManager;
using Azure.ResourceManager.ComputeLimit;
using Azure.ResourceManager.Resources;
using NUnit.Framework;

namespace Azure.ResourceManager.ComputeLimit.Tests.Samples
{
    public class Sample1_VmFamilies
    {
        [Test]
        [Ignore(&#34;Only verifying that the sample builds&#34;)]
        public async Task ListVmFamilies()
        {
            #region Snippet:ComputeLimitSample_ListVmFamilies
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();

            // List all VM family resources in a specific location
            string location = &#34;eastus&#34;;
            await foreach (ComputeLimitVmFamilyResource vmFamily in subscription.GetComputeLimitVmFamiliesAsync(location))
            {
                Console.WriteLine($&#34;VM Family: {vmFamily.Data.Name}&#34;);
            }
            #endregion
        }

        [Test]
        [Ignore(&#34;Only verifying that the sample builds&#34;)]
        public async Task DisableFeature()
        {
            #region Snippet:ComputeLimitSample_DisableFeature
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();

            // Get a specific compute limit feature and disable it
            string location = &#34;eastus&#34;;
            string featureName = &#34;SharedQuota&#34;;
            ComputeLimitFeatureResource feature = await subscription
                .GetComputeLimitFeatureAsync(location, featureName);

            // Disable the feature
            await feature.DisableAsync(WaitUntil.Completed);
            Console.WriteLine($&#34;Feature &#39;{featureName}&#39; has been disabled.&#34;);
            #endregion
        }

        [Test]
        [Ignore(&#34;Only verifying that the sample builds&#34;)]
        public async Task ListGuestSubscriptions()
        {
            #region Snippet:ComputeLimitSample_ListGuestSubscriptions
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();

            // List all guest subscriptions that share quota with this subscription
            await foreach (ComputeLimitGuestSubscriptionResource guestSub in subscription.GetComputeLimitGuestSubscriptionsAsync())
            {
                Console.WriteLine($&#34;Guest subscription: {guestSub.Data.Name}&#34;);
            }
            #endregion
        }
    }
}
```

### Step 2: Add or update code snippets

The three snippet regions defined in the test file above map to the README placeholders as follows:

| Snippet Name | Test method | README location |
|---|---|---|
| `ComputeLimitSample_ListVmFamilies` | `ListVmFamilies()` | Under `### List VM families for a subscription location` |
| `ComputeLimitSample_DisableFeature` | `DisableFeature()` | Under `### Get and disable a compute limit feature` |
| `ComputeLimitSample_ListGuestSubscriptions` | `ListGuestSubscriptions()` | Under `### List guest subscriptions sharing compute quota` |

Each README placeholder block is already included in the Step 1 README edits above.

### Step 3: Verify README structure

The README at `sdk/computelimit/Azure.ResourceManager.ComputeLimit/README.md` currently **has** all required top-level sections. The following need content improvements:

| Section | Status | Action |
|---|---|---|
| Getting started → Install the package | ✅ Complete | — |
| Getting started → Prerequisites | ✅ Complete | — |
| Getting started → Authenticate the client | ✅ Complete | — |
| Key concepts | ❌ Generic boilerplate | Replace with service-specific content (see Step 1) |
| Examples | ❌ No code samples | Add snippet placeholders + test file (see Steps 1–2) |
| Troubleshooting | ✅ Complete | — |
| Next steps | ✅ Complete | — |
| Contributing | ✅ Complete | — |

Use `sdk/keyvault/Azure.Security.KeyVault.Secrets/README.md` as the canonical reference for section formatting and tone.

### Step 4: Validate

Run these commands in order. Each must succeed before proceeding to the next.

1. `dotnet build sdk/computelimit/Azure.ResourceManager.ComputeLimit/`
2. `dotnet test sdk/computelimit/Azure.ResourceManager.ComputeLimit/ --filter TestCategory!=Live`
3. `eng/scripts/Update-Snippets.ps1 computelimit` — injects snippet code into README placeholder blocks; verify with `git diff` that README was updated
4. `eng/scripts/Export-API.ps1 computelimit` — regenerates API listing files (no public API changes expected, but run to confirm)
5. `dotnet format sdk/computelimit/Azure.ResourceManager.ComputeLimit/` — ensures consistent formatting

&gt; **Note:** The exact method signatures for `GetComputeLimitVmFamiliesAsync`, `GetComputeLimitFeatureAsync`, `DisableAsync`, and `GetComputeLimitGuestSubscriptionsAsync` should be verified against the generated extension methods in `src/Generated/Extensions/ComputeLimitExtensions.cs` and the resource files before writing the samples. Adjust parameter names/types as needed to match the actual generated API.



